#include <bits/stdc++.h>
using namespace std;
int n,m,t[1000006];
bool check(int mid){
    long long sum=0;
    for(int i=1;i<=n;i++)
        if(t[i]>mid)sum+=t[i]-mid;
    return sum>=m;
}
int main(){
    cin>>n>>m;
    int l=0,r=0;
    for(int i=1;i<=n;i++){
        cin>>t[i];
        r=max(r,t[i]);
    }
    while(l<r){
        int mid=(l+r+1)/2;
        if(check(mid))l=mid;
        else r=mid-1;
    }
    cout<<l;
    return 0;
}
